// قائمة روابط الصور (7 صور)
const bgImages = [
  'https://i.imgur.com/CSzmbEm.jpeg',  // الصورة 1 (الأصلية)
  'https://media1.tenor.com/m/RaoQ4SRgZNMAAAAC/ass-sexy.gif',  // الصورة 2 - استبدلها برابط صورتك
  'https://i.imgur.com/nzmxCZj.jpeg',   // الصورة 3 - استبدلها
  'https://i.imgur.com/elOhnJJ.jpeg',   // الصورة 4 - استبدلها
  'https://media1.tenor.com/m/pL8t5v65cYIAAAAC/seyeon-fruitseyeon-asian-girl-cute.gif',   // الصورة 5 - استبدلها
  'https://media1.tenor.com/m/iDsm5bg4JcMAAAAd/cute-girl-japan.gif',   // الصورة 6 - استبدلها
  'https://media1.tenor.com/m/-VuHT84kBcwAAAAC/hayoung-v-sexy-girl-big-boobs.gif'    // الصورة 7 - استبدلها
];

let currentIndex = 0;
let overlayDiv = null;
let intervalId = null;
let isTransitioning = false;
let transitionTimeout = null;
let imageLoadTimeout = null;

// دالة لإزالة أي خلفية قديمة
function removeExistingBackground() {
  const existingOverlay = document.getElementById('dynamic-bg-overlay');
  if (existingOverlay) existingOverlay.remove();
  if (overlayDiv) overlayDiv = null;
}

// دالة لإنشاء عنصر الخلفية
function createBackgroundElement(imageUrl, initialOpacity = 0) {
  const bgDiv = document.createElement('div');
  bgDiv.id = 'dynamic-bg-overlay';
  bgDiv.style.position = 'fixed';
  bgDiv.style.top = '0';
  bgDiv.style.left = '0';
  bgDiv.style.width = '100%';
  bgDiv.style.height = '100%';
  bgDiv.style.zIndex = '-10';
  bgDiv.style.backgroundImage = `url('${imageUrl}')`;
  bgDiv.style.backgroundSize = 'cover';
  bgDiv.style.backgroundPosition = 'center';
  bgDiv.style.backgroundRepeat = 'no-repeat';
  bgDiv.style.opacity = initialOpacity;
  bgDiv.style.transition = 'opacity 3s ease-in-out'; // 3 ثواني لتلاشي البطيء
  bgDiv.style.pointerEvents = 'none';
  return bgDiv;
}

// دالة لتغيير الصورة مع تأثير تلاشي
function changeBackgroundWithFade() {
  if (isTransitioning) return;
  isTransitioning = true;

  // حساب الصورة التالية
  const nextIndex = (currentIndex + 1) % bgImages.length;
  const nextImageUrl = bgImages[nextIndex];

  // إنشاء عنصر الخلفية الجديدة (يبدأ شفافاً)
  const newBg = createBackgroundElement(nextImageUrl, 0);
  document.body.appendChild(newBg);

  // التأكد من تحميل الصورة قبل بدء الانتقال
  const img = new Image();
  img.onload = () => {
    if (imageLoadTimeout) clearTimeout(imageLoadTimeout);

    // إخفاء الخلفية القديمة أولاً
    if (overlayDiv) {
      overlayDiv.style.opacity = '0';
    }

    // بعد 3 ثواني (مدة التلاشي)، نُظهر الخلفية الجديدة
    setTimeout(() => {
      newBg.style.opacity = '1';

      // نزيل الخلفية القديمة بعد أن تختفي تماماً وتظهر الجديدة
      setTimeout(() => {
        if (overlayDiv) overlayDiv.remove();
        overlayDiv = newBg;
        currentIndex = nextIndex;
        isTransitioning = false;
      }, 3100); // 3.1 ثانية للتأكد
    }, 50);
  };

  img.onerror = () => {
    console.warn('فشل تحميل الصورة، انتقل إلى التالية');
    if (imageLoadTimeout) clearTimeout(imageLoadTimeout);
    // تخطي هذه الصورة في حالة الخطأ
    imageLoadTimeout = setTimeout(() => {
      if (newBg) newBg.remove();
      isTransitioning = false;
      // تغيير المؤشر إلى التالي تلقائياً
      currentIndex = (currentIndex + 1) % bgImages.length;
      changeBackgroundWithFade();
    }, 100);
  };

  img.src = nextImageUrl;
}

// دالة لبدء العروض
function startSlideshow() {
  if (intervalId) clearInterval(intervalId);

  // إعداد الخلفية الأولية
  removeExistingBackground();
  overlayDiv = createBackgroundElement(bgImages[0], 1);
  document.body.appendChild(overlayDiv);
  currentIndex = 0;

  // كل 6 ثواني (3 ثواني ثبات + 3 ثواني تلاشي) يتم التبديل
  intervalId = setInterval(() => {
    if (!isTransitioning) {
      changeBackgroundWithFade();
    }
  }, 6000); // 6 ثواني كاملة لكل صورة
}

// مراقبة تحميل الصفحة
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', startSlideshow);
} else {
  startSlideshow();
}

// تنظيف عند إعادة التحميل
window.addEventListener('beforeunload', () => {
  if (intervalId) clearInterval(intervalId);
  if (transitionTimeout) clearTimeout(transitionTimeout);
  if (imageLoadTimeout) clearTimeout(imageLoadTimeout);
});
